@@ -365,7 +365,7 @@ process_args(int argc, char *argv[])
                         }

                         if (stripes == 0) {
-                                openflags |= O_LOV_DELAY_CREATE;
+                                openflags |= O_LOV_DELAY_CREATE_MASK;
                         } else {
                                 fatal(0, "non-zero --stripes value "
                                          "not yet supported.\n");
